      "new_env_vars": [
        "INVENTORY_API_TIMEOUT_MS — configurable timeout for outbound API calls",
        "SYNC_RETRY_MAX_ATTEMPTS — configurable retry count",
        "SYNC_RETRY_BACKOFF_BASE_MS — configurable backoff base"
      ],
      "new_services": [],
      "new_queues_topics": [],
      "config_changes": [
        "Add liveness probe target: GET /health",
        "Add readiness probe target: GET /health (checks last successful sync recency)",
        "Configure alerting rule: 'time since last successful sync > 15 minutes'"
      ],
      "infra_provisioning": []
    },
    "database_safety": {
      "has_migrations": false,
      "reversible": true,
